def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        scale = 1.0
        complexity = 0.0
        modifier = 1.0
        acc_penalty = 0.0
        acc_bonus = 0.0
        history = []
        for x in range(1, 15):
            if x % 2 == 0 and cap % (x + 3) == 0:
                complexity += np.tanh(ratio * x) * (x ** 1.1)
            if x % 5 == 0:
                scale *= 1 + 0.03 * (np.sin(x) - np.cos(x * ratio))
            if ratio < 0.3 * x:
                val = np.exp(-ratio * x) * (x + np.log1p(cap))
                base_score += val * scale
            else:
                val = (np.sqrt(x * cap) + ratio ** 2) / (1 + np.exp(x - ratio))
                base_score += val * (1/scale)
            if cap % (x+1) == 0 and x % 3 == 1:
                acc_bonus += np.log1p(x * ratio) * 0.7
            if item * x - cap > 0 and (item * x - cap) % (x + 4) == 0:
                acc_penalty += ((item * x - cap) / (x + 5)) ** 0.9
            if x == 10:
                for y in range(1, 5):
                    diff = abs((cap / (y + 1)) - (item * y))
                    if diff < 1e-5:
                        modifier *= 1.2
                    elif diff < 2:
                        modifier *= 0.85
                    else:
                        modifier *= 0.95 - 0.01 * y
            history.append(base_score)
        avg_hist = sum(history) / len(history)
        complexity = complexity * np.log1p(cap) - acc_penalty * 0.9 + acc_bonus * 1.4
        final_score = (base_score + complexity + avg_hist) * modifier
        if ratio > 1.2:
            final_score *= 1.25
        elif 0.9 <= ratio <= 1.2:
            final_score *= 0.92
        else:
            final_score *= 0.75 + 0.3 * np.exp(-ratio)
        if cap % 3 == 0:
            final_score *= 0.97
        else:
            final_score *= 1.03
        if final_score < 0:
            priorities[i] = -final_score / (np.sqrt(cap + 2) + 1) * (1 + ratio ** 1.5)
        else:
            priorities[i] = -final_score * (np.log1p(cap + item) ** 0.8) / (cap + 5)
        if priority := priorities[i] < 0:
            priorities[i] = priorities[i] * (1 + 0.05 * (cap % 4))
        else:
            priorities[i] = priorities[i] * (0.95 + 0.03 * (item % 2))
    return priorities
